sql:
SELECT MAX(total_entries) AS highest_total_entries
FROM ridership_reports
WHERE report_date = '2014-12-27';

SELECT SUM(total_entries) AS total_entries_on_day
FROM ridership_reports
WHERE report_date = '2014-12-27';

SELECT SUM(entries) AS total_entries, SUM(exits) AS total_exits
FROM entries_exits
WHERE station_id = 0 AND date = '2023-01-01';

external_knowledge:
- 'storm-battered stations' refers to stations that experienced major alerts (impact = 'major');
- 'massive crowds came and went' refers to total daily entries and exits;
- 'flooded with people' refers to having more than 10 days of records.

sql:
SELECT SUM(entries) AS total_entries
FROM entries_exits
WHERE station_id = (SELECT station_id FROM stations WHERE station_name = 'Lexington Ave');

SELECT station_id, SUM(entries) AS total_entries, SUM(exits) AS total_exits
FROM entries_exits
GROUP BY station_id;

SELECT station_id, SUM(total_entries) AS total_entries_sum
FROM ridership_reports
GROUP BY station_id;

SELECT total_entries
FROM ridership_reports
WHERE report_id = 0;

SELECT total_entries
FROM ridership_reports
WHERE station_id = 1 AND report_date = '2014-12-27';
